PyDoc_STRVAR(__pyx_doc_6qtrees_4tree_5_tree_4Tree_20compute_partial_dependence, "Partial dependence of the response on the ``target_feature`` set.\n\n        For each sample in ``X`` a tree traversal is performed.\n        Each traversal starts from the root with weight 1.0.\n\n        At each non-leaf node that splits on a target feature, either\n        the left child or the right child is visited based on the feature\n        value of the current sample, and the weight is not modified.\n        At each non-leaf node that splits on a complementary feature,\n        both children are visited and the weight is multiplied by the fraction\n        of training samples which went to each child.\n\n        At each leaf, the value of the node is multiplied by the current\n        weight (weights sum to 1 for all visited terminal nodes).\n\n        Parameters\n        ----------\n        X : view on 2d ndarray, shape (n_samples, n_target_features)\n            The grid points on which the partial dependence should be\n            evaluated.\n        target_features : view on 1d ndarray, shape (n_target_features)\n            The set of target features for which the partial dependence\n            should be evaluated.\n        out : view on 1d ndarray, shape (n_samples)\n            The value of the partial dependence function on each grid\n            point.\n        ");
static PyMethodDef __pyx_mdef_6qtrees_4tree_5_tree_4Tree_21compute_partial_dependence = {"compute_partial_dependence", (PyCFunction)(void(*)(void))(__Pyx_PyCFunction_FastCallWithKeywords)__pyx_pw_6qtrees_4tree_5_tree_4Tree_21compute_partial_dependence, __Pyx_METH_FASTCALL|METH_KEYWORDS, __pyx_doc_6qtrees_4tree_5_tree_4Tree_20compute_partial_dependence};
